/* ---------------------------------------------------------------------------
 * ThemeInit — pre-hydration theme injection (suite 14/P01)
 *
 * Renders an inline <script> that reads localStorage "theme" (or falls back
 * to prefers-color-scheme) and sets data-theme on <html> before paint, so
 * we never flash the wrong theme during hydration.
 * --------------------------------------------------------------------------- */

const SCRIPT = `(function(){try{var s=localStorage.getItem('theme');var t=(s==='light'||s==='dark')?s:(window.matchMedia&&window.matchMedia('(prefers-color-scheme: light)').matches?'light':'dark');document.documentElement.setAttribute('data-theme',t);}catch(e){document.documentElement.setAttribute('data-theme','dark');}})();`;

export function ThemeInit() {
  return <script dangerouslySetInnerHTML={{ __html: SCRIPT }} />;
}

export default ThemeInit;

